    const int sampleCount = 10;
    int iterPerSample = Iterations / sampleCount;
    double[] samples = new double[sampleCount];

    for (int s = 0; s < sampleCount; s++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < iterPerSample; i++)
            action();
        sw.Stop();
        samples[s] = sw.Elapsed.TotalNanoseconds / iterPerSample;
    }

    Array.Sort(samples);
    double median = samples[sampleCount / 2];
    double mean = samples.Average();
    double min = samples[0];
    double max = samples[^1];

    // StdDev
    double sumSqDiff = samples.Sum(x => (x - mean) * (x - mean));
    double stddev = Math.Sqrt(sumSqDiff / sampleCount);

    Console.WriteLine($"{name,-25} median: {FormatNs(median),10} | mean: {FormatNs(mean),10} | stddev: {FormatNs(stddev),10} | min: {FormatNs(min),10} | max: {FormatNs(max),10}");
}

